1	export type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	
3	export type Customer = { yearsWithMHPCO: number };
4	
5	export type Damage = { itemType: string; amount: number };
6	
7	export type Incident = { cause?: string; damages: Damage[] };
8	
9	export type Step = {
10	  op: string;
11	  items?: Item[];
12	  policy?: number;
13	  incident?: Incident;
14	};
15	
16	export type Scenario = {
17	  customer: Customer;
18	  steps: Step[];
19	};
20	
21	export type ScenarioResult = {
22	  results: StepResult[];
23	};
24	
25	const PROCESSING_FEE = 5;
26	
27	const BASE_PREMIUMS: Record<string, number> = {
28	  sword: 100,
29	  amulet: 60,
30	  staff: 80,
31	  potion: 40,
32	  rune: 25,
33	  moonstone: 25,
34	};
35	
36	const INSURANCE_VALUES: Record<string, number> = {
37	  sword: 1000,
38	  amulet: 600,
39	  staff: 800,
40	  potion: 400,
41	  rune: 250,
42	  moonstone: 250,
43	};
44	
45	const DEDUCTIBLE = 100;
46	const CAP_MULTIPLIER = 2;
47	
48	type StepResult = { premium?: number; payout?: number; remainingCap?: number };
49	
50	const BLOCK_SIZE = 3;
51	const BLOCK_PREMIUM = 60;
52	
53	const CURSE_SURCHARGE_RATE = 0.5;
54	const FIRST_INSURANCE_RATE = 0.1;
55	const HIGH_ENCHANTMENT_RATE = 0.3;
56	const HIGH_ENCHANTMENT_THRESHOLD = 5;
57	const LOYALTY_DISCOUNT_RATE = 0.2;
58	const LOYALTY_YEARS_THRESHOLD = 2;
59	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
60	
61	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
62	
63	const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
64	
65	const groupKeyFor = (item: Item, index: number): string =>
66	  COMPONENT_TYPES.has(item.type) ? item.type : `item:${index}`;
67	
68	const groupItemsForPricing = (items: Item[]): Item[][] => {
69	  const groups = new Map<string, Item[]>();
70	  items.forEach((item, index) => {
71	    const key = groupKeyFor(item, index);
72	    const group = groups.get(key) ?? [];
73	    group.push(item);
74	    groups.set(key, group);
75	  });
76	  return [...groups.values()];
77	};
78	
79	const premiumForGroup = (group: Item[]): number =>
80	  group.length === BLOCK_SIZE
81	    ? BLOCK_PREMIUM
82	    : group.reduce((total, item) => total + basePremiumFor(item), 0);
83	
84	const totalBasePremiumFor = (items: Item[]): number =>
85	  groupItemsForPricing(items).reduce((total, group) => total + premiumForGroup(group), 0);
86	
87	const itemSurchargeFor = (
88	  items: Item[],
89	  qualifies: (item: Item) => boolean,
90	  rate: number,
91	): number =>
92	  items.reduce(
93	    (total, item) => (qualifies(item) ? total + basePremiumFor(item) * rate : total),
94	    0,
95	  );
96	
97	const isCursed = (item: Item): boolean => item.cursed === true;
98	
99	const isHighlyEnchanted = (item: Item): boolean =>
100	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
101	
102	type QuoteContext = { customer: Customer; quoteIndex: number };
103	
104	type PolicyModifier = (base: number, items: Item[], context: QuoteContext) => number;
105	
106	const discountWhen =
107	  (rate: number, qualifies: (context: QuoteContext) => boolean): PolicyModifier =>
108	  (base, _items, context) =>
109	    qualifies(context) ? -(base * rate) : 0;
110	
111	const isLoyalCustomer = ({ customer }: QuoteContext): boolean =>
112	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
113	
114	const isFollowUpQuote = ({ quoteIndex }: QuoteContext): boolean => quoteIndex > 0;
115	
116	const cursedSurcharge: PolicyModifier = (_base, items) =>
117	  itemSurchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
118	
119	const highEnchantmentSurcharge: PolicyModifier = (_base, items) =>
120	  itemSurchargeFor(items, isHighlyEnchanted, HIGH_ENCHANTMENT_RATE);
121	
122	const firstInsuranceSurcharge: PolicyModifier = (base) => base * FIRST_INSURANCE_RATE;
123	
124	const loyaltyDiscount = discountWhen(LOYALTY_DISCOUNT_RATE, isLoyalCustomer);
125	
126	const followUpDiscount = discountWhen(FOLLOW_UP_DISCOUNT_RATE, isFollowUpQuote);
127	
128	const POLICY_MODIFIERS: PolicyModifier[] = [
129	  cursedSurcharge,
130	  highEnchantmentSurcharge,
131	  firstInsuranceSurcharge,
132	  loyaltyDiscount,
133	  followUpDiscount,
134	];
135	
136	const sumModifiers = (base: number, items: Item[], context: QuoteContext): number =>
137	  POLICY_MODIFIERS.reduce((total, modifier) => total + modifier(base, items, context), 0);
138	
139	const quotePremium = (items: Item[], context: QuoteContext): number => {
140	  const base = totalBasePremiumFor(items);
141	  return Math.ceil(base + sumModifiers(base, items, context) + PROCESSING_FEE);
142	};
143	
144	const insuranceValueFor = (item: Item): number => INSURANCE_VALUES[item.type] ?? 0;
145	
146	const insuranceSumOf = (items: Item[]): number =>
147	  items.reduce((sum, item) => sum + insuranceValueFor(item), 0);
148	
149	const payoutForDamage = (damage: Damage): number => Math.max(0, damage.amount - DEDUCTIBLE);
150	
151	const processClaim = (step: Step, scenario: Scenario): StepResult => {
152	  const policyStep = scenario.steps[step.policy ?? 0];
153	  const policyItems = policyStep.items ?? [];
154	  const damages = step.incident?.damages ?? [];
155	  const cap = CAP_MULTIPLIER * insuranceSumOf(policyItems);
156	  const payout = damages.reduce((total, damage) => total + payoutForDamage(damage), 0);
157	  return { payout, remainingCap: cap - payout };
158	};
159	
160	const processStep = (step: Step, scenario: Scenario, quoteIndex: number): StepResult => {
161	  if (step.op === "claim") return processClaim(step, scenario);
162	  return { premium: quotePremium(step.items ?? [], { customer: scenario.customer, quoteIndex }) };
163	};
164	
165	export const runScenario = (scenario: Scenario): ScenarioResult => ({
166	  results: scenario.steps.map((step, index) => processStep(step, scenario, index)),
167	});
